from impacket.ldap import ldap

try:
    l = ldap.LDAPConnection('ldap://10.129.16.228', 'DC=garfield,DC=htb')
    l.login('', '')
    print("LDAP anonymous bind OK")

    # Simple search for all users
    sr = l.search(searchBase='DC=garfield,DC=htb',
                  searchFilter='(objectCategory=person)',
                  attributes=['sAMAccountName','description','memberOf','userAccountControl','distinguishedName'])

    for item in sr:
        try:
            if not isinstance(item, dict):
                # Try to access attributes
                entry = item['attributes']
                vals = {}
                for attr in entry:
                    name = str(attr['type'])
                    val_list = [str(v) for v in attr['vals']]
                    vals[name] = val_list
                if 'sAMAccountName' in vals:
                    sam = vals['sAMAccountName'][0]
                    desc = vals.get('description', [''])[0]
                    uac = vals.get('userAccountControl', [''])[0]
                    dn = vals.get('distinguishedName', [''])[0]
                    groups = vals.get('memberOf', [])
                    print(f"User: {sam}")
                    if desc: print(f"  desc: {desc}")
                    if uac: print(f"  UAC: {uac}")
                    if dn: print(f"  DN: {dn}")
                    for g in groups[:3]:
                        print(f"  group: {g}")
                    print()
        except Exception as inner:
            pass

except Exception as e:
    print(f"LDAP error: {e}")
PYEOF

